import threading
import time
import logging
import uuid

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class TransactionError(Exception):
    pass

class InsufficientFundsError(TransactionError):
    pass

class ATM:
    def __init__(self, atm_id, initial_cash):
        self.atm_id = atm_id
        self.cash_balance = initial_cash
        self.lock = threading.Lock()
        self.transaction_log = [] # Store transaction details for auditing
        logging.info(f"ATM {self.atm_id} initialized with cash: {self.cash_balance}")

    def deposit(self, amount, account_id):
        with self.lock:
            if amount <= 0:
                raise ValueError("Deposit amount must be positive.")
            self.cash_balance += amount
            transaction_id = uuid.uuid4()
            self.transaction_log.append({
                'transaction_id': transaction_id,
                'type': 'deposit',
                'account_id': account_id,
                'amount': amount,
                'timestamp': time.time()
            })
            logging.info(f"ATM {self.atm_id}: Deposit of {amount} into account {account_id}. New ATM balance: {self.cash_balance}")
            return transaction_id

    def withdraw(self, amount, account_id):
        with self.lock:
            if amount <= 0:
                raise ValueError("Withdrawal amount must be positive.")
            if amount > self.cash_balance:
                raise InsufficientFundsError("Insufficient funds in ATM.")

            self.cash_balance -= amount
            transaction_id = uuid.uuid4()
            self.transaction_log.append({
                'transaction_id': transaction_id,
                'type': 'withdrawal',
                'account_id': account_id,
                'amount': amount,
                'timestamp': time.time()
            })
            logging.info(f"ATM {self.atm_id}: Withdrawal of {amount} from account {account_id}. New ATM balance: {self.cash_balance}")
            return transaction_id

    def get_balance(self):
        with self.lock:
            return self.cash_balance

    def audit_transaction(self, transaction_id):
        with self.lock:
            for transaction in self.transaction_log:
                if transaction['transaction_id'] == transaction_id:
                    return transaction
            return None

