class BankController:
    def __init__(self):
        self.atms = {}
        self.accounts = {}
        self.account_locks = {} # Separate locks for each account
        self.transaction_locks = {} # Locks for specific transactions
        self.central_ledger = [] # Centralized transaction log for auditing
        self.ledger_lock = threading.Lock() # Lock for accessing the central ledger

    def add_atm(self, atm_id, initial_cash):
        if atm_id in self.atms:
            raise ValueError(f"ATM with ID {atm_id} already exists.")
        self.atms[atm_id] = ATM(atm_id, initial_cash)
        logging.info(f"ATM {atm_id} added to the network.")

    def create_account(self, account_id, initial_balance):
        if account_id in self.accounts:
            raise ValueError(f"Account with ID {account_id} already exists.")
        self.accounts[account_id] = Account(account_id, initial_balance)
        self.account_locks[account_id] = threading.Lock()
        logging.info(f"Account {account_id} created.")

    def deposit(self, atm_id, account_id, amount):
        if atm_id not in self.atms:
            raise ValueError(f"ATM with ID {atm_id} not found.")
        if account_id not in self.accounts:
            raise ValueError(f"Account with ID {account_id} not found.")

        try:
            atm = self.atms[atm_id]
            with self.account_locks[account_id]: # Lock the account
                transaction_id = atm.deposit(amount, account_id)
                self.accounts[account_id].deposit(amount)
                self._record_transaction(transaction_id, 'deposit', atm_id, account_id, amount)
                return transaction_id
        except Exception as e:
            logging.error(f"Deposit failed: {e}")
            raise

    def withdraw(self, atm_id, account_id, amount):
        if atm_id not in self.atms:
            raise ValueError(f"ATM with ID {atm_id} not found.")
        if account_id not in self.accounts:
            raise ValueError(f"Account with ID {account_id} not found.")

        try:
            atm = self.atms[atm_id]
            with self.account_locks[account_id]: # Lock the account
                transaction_id = atm.withdraw(amount, account_id)
                self.accounts[account_id].withdraw(amount)
                self._record_transaction(transaction_id, 'withdrawal', atm_id, account_id, amount)
                return transaction_id
        except Exception as e:
            logging.error(f"Withdrawal failed: {e}")
            raise

    def get_account_balance(self, account_id):
        if account_id not in self.accounts:
            raise ValueError(f"Account with ID {account_id} not found.")
        return self.accounts[account_id].get_balance()

    def get_atm_balance(self, atm_id):
        if atm_id not in self.atms:
            raise ValueError(f"ATM with ID {atm_id} not found.")
        return self.atms[atm_id].get_balance()

    def _record_transaction(self, transaction_id, transaction_type, atm_id, account_id, amount):
        with self.ledger_lock:
            self.central_ledger.append({
                'transaction_id': transaction_id,
                'type': transaction_type,
                'atm_id': atm_id,
                'account_id': account_id,
                'amount': amount,
                'timestamp': time.time()
            })
            logging.info(f"Transaction {transaction_id} recorded in central ledger.")

    def audit_transaction(self, transaction_id):
        with self.ledger_lock:
            for transaction in self.central_ledger:
                if transaction['transaction_id'] == transaction_id:
                    return transaction
            return None

    def reconcile_balances(self):
        """
        Performs reconciliation between ATM cash balances and account balances.
        This is a critical function for ensuring data integrity and detecting discrepancies.
        """
        logging.info("Starting balance reconciliation process...")
        discrepancies = []

        for account_id, account in self.accounts.items():
            expected_balance = account.get_balance()
            calculated_balance = 0

            # Calculate balance from transaction history
            with self.ledger_lock:
                for transaction in self.central_ledger:
                    if transaction['account_id'] == account_id:
                        if transaction['type'] == 'deposit':
                            calculated_balance += transaction['amount']
                        elif transaction['type'] == 'withdrawal':
                            calculated_balance -= transaction['amount']

            if abs(expected_balance - calculated_balance) > 0.001: # Allow for minor floating-point differences
                discrepancies.append({
                    'account_id': account_id,
                    'expected_balance': expected_balance,
                    'calculated_balance': calculated_balance
                })
                logging.warning(f"Balance discrepancy found for account {account_id}: Expected {expected_balance}, Calculated {calculated_balance}")

        for atm_id, atm in self.atms.items():
            expected_cash = atm.get_balance()
            calculated_cash = 0

            # Calculate ATM cash from transaction history
            with self.ledger_lock:
                for transaction in self.central_ledger:
                    if transaction['atm_id'] == atm_id:
                        if transaction['type'] == 'deposit':
                            calculated_cash -= transaction['amount'] # Cash leaves ATM during deposit
                        elif transaction['type'] == 'withdrawal':
                            calculated_cash += transaction['amount'] # Cash enters ATM during withdrawal

            initial_cash = atm.cash_balance - calculated_cash # Adjust for initial cash
            if abs(expected_cash - initial_cash) > 0.001:
                discrepancies.append({
                    'atm_id': atm_id,
                    'expected_cash': expected_cash,
                    'calculated_cash': initial_cash
                })
                logging.warning(f"Cash discrepancy found for ATM {atm_id}: Expected {expected_cash}, Calculated {initial_cash}")

        if discrepancies:
            logging.error("Balance reconciliation found discrepancies. Review logs for details.")
        else:
            logging.info("Balance reconciliation completed. No discrepancies found.")

        return discrepancies
